/*
 * Modular OS Kernel Structure
 * Demonstrates how modern operating systems organize kernel code into modules
 * Each module has a clean interface and can be loaded/removed independently
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Module Management Structures */
typedef int (*module_init_t)(void);
typedef void (*module_cleanup_t)(void);

typedef struct {
 const char *name;
 module_init_t init;
 module_cleanup_t cleanup;
 int loaded;
} kernel_module_t;

/* Process Management Module */
typedef struct {
 int pid;
 char name[64];
 int state; // 0=NEW, 1=READY, 2=RUNNING, 3=BLOCKED, 4=TERMINATED
 unsigned int memory_used;
} process_t;

static process_t *process_table[64];
static int process_count = 0;

int process_module_init(void) {
 printf("[PROCESS_MGR] Initializing Process Management Module\n");
 memset(process_table, 0, sizeof(process_table));
 return 0;
}

void process_module_cleanup(void) {
 printf("[PROCESS_MGR] Cleaning up Process Management Module\n");
 for (int i = 0; i < process_count; i++) {
 free(process_table[i]);
 }
}

int create_process(const char *name) {
 process_t *proc = (process_t *)malloc(sizeof(process_t));
 if (!proc) return -1;

 proc->pid = process_count + 1;
 strncpy(proc->name, name, 63);
 proc->state = 1; // READY
 proc->memory_used = 4096; // Default 4KB

 process_table[process_count++] = proc;
 printf("[PROCESS_MGR] Created process: %s (PID: %d)\n", name, proc->pid);
 return proc->pid;
}

void list_processes(void) {
 printf("\n--- Process Table ---\n");
 printf("PID\tName\t\tState\tMemory\n");
 for (int i = 0; i < process_count; i++) {
 const char *state_str[] = {"NEW", "READY", "RUNNING", "BLOCKED", "TERMINATED"};
 printf("%d\t%s\t%s\t%dKB\n", 
 process_table[i]->pid, 
 process_table[i]->name,
 state_str[process_table[i]->state],
 process_table[i]->memory_used / 1024);
 }
 printf("\n");
}

/* Memory Management Module */
#define MAX_PAGES 256
typedef struct {
 int page_number;
 int allocated;
 int owner_pid;
} memory_page_t;

static memory_page_t memory_pool[MAX_PAGES];

int memory_module_init(void) {
 printf("[MEMORY_MGR] Initializing Memory Management Module\n");
 memset(memory_pool, 0, sizeof(memory_pool));
 return 0;
}

void memory_module_cleanup(void) {
 printf("[MEMORY_MGR] Cleaning up Memory Management Module\n");
}

void *allocate_memory(int pid, size_t size) {
 int pages_needed = (size + 4095) / 4096;
 int allocated = 0;

 for (int i = 0; i < MAX_PAGES && allocated < pages_needed; i++) {
 if (!memory_pool[i].allocated) {
 memory_pool[i].allocated = 1;
 memory_pool[i].owner_pid = pid;
 allocated++;
 }
 }

 printf("[MEMORY_MGR] Allocated %d pages for PID %d\n", pages_needed, pid);
 return (void *)(allocated * 4096); // Simplified
}

/* File System Module */
typedef struct {
 char filename[64];
 char content[256];
 int size;
 int owner_pid;
} file_entry_t;

static file_entry_t file_system[32];
static int file_count = 0;

int filesystem_module_init(void) {
 printf("[FILESYSTEM] Initializing File System Module\n");
 memset(file_system, 0, sizeof(file_system));
 return 0;
}

void filesystem_module_cleanup(void) {
 printf("[FILESYSTEM] Cleaning up File System Module\n");
}

int create_file(const char *filename, const char *content, int pid) {
 if (file_count >= 32) return -1;

 strncpy(file_system[file_count].filename, filename, 63);
 strncpy(file_system[file_count].content, content, 255);
 file_system[file_count].size = strlen(content);
 file_system[file_count].owner_pid = pid;

 printf("[FILESYSTEM] Created file: %s (size: %d bytes)\n", 
 filename, file_system[file_count].size);
 return file_count++;
}

/* Kernel Core - Module Registry */
static kernel_module_t kernel_modules[] = {
 {"process_manager", process_module_init, process_module_cleanup, 0},
 {"memory_manager", memory_module_init, memory_module_cleanup, 0},
 {"filesystem", filesystem_module_init, filesystem_module_cleanup, 0},
};

#define NUM_MODULES (sizeof(kernel_modules) / sizeof(kernel_module_t))

void kernel_init(void) {
 printf("=== Modular Kernel Initialization ===\n\n");

 for (int i = 0; i < NUM_MODULES; i++) {
 if (kernel_modules[i].init() == 0) {
 kernel_modules[i].loaded = 1;
 printf("[KERNEL] Module '%s' loaded successfully\n", 
 kernel_modules[i].name);
 }
 }
 printf("\n=== Kernel Ready ===\n\n");
}

void kernel_shutdown(void) {
 printf("\n=== Kernel Shutdown ===\n");

 for (int i = NUM_MODULES - 1; i >= 0; i--) {
 if (kernel_modules[i].loaded) {
 kernel_modules[i].cleanup();
 kernel_modules[i].loaded = 0;
 }
 }
}

/* Main - Demonstrates modular kernel operation */
int main(void) {
 // Initialize kernel with all modules
 kernel_init();

 // Create some processes
 int pid1 = create_process("shell");
 int pid2 = create_process("httpd");
 int pid3 = create_process("database");

 // Allocate memory for processes
 allocate_memory(pid1, 8192); // 8KB
 allocate_memory(pid2, 16384); // 16KB
 allocate_memory(pid3, 12288); // 12KB

 // Create files
 create_file("/etc/config", "timeout=30\nport=8080", pid1);
 create_file("/var/log/syslog", "System started successfully", pid2);

 // List all processes
 list_processes();

 // Simulate loading/unloading modules
 printf("[KERNEL] Simulating module unload...\n");
 // In real OS: unload_module("filesystem");

 // Shutdown
 kernel_shutdown();

 return 0;
}
